  ('heelevel3-9e7ddffc-moex-00075', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '在計算本國之國民所得時，有關本國人王先生在美國出差之工作所得，下列敘述何者正確？', '["不應列入GNP計算", "應列入為淨國民收入（NetNationalIncome）項目內", "應該列入GDP", "應該同時列入本國之GDP與GNP"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00076', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '提款機的普及讓貨幣的流通速度加快。在古典二分（classicaldichotomy）的前提之下，下列何者 為最有可能發生的結果？', '["所得提高", "所得降低", "實質貨幣數量提高", "實質貨幣數量降低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00077', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '若世界各國生產函數為Y=AKαL1-α，α (0,1)，其中Y為產出，A為技術水準，L為勞動，K為資本。據 此生產函數，關於新古典成長模型之收斂假說，下列敘述何者正確？', '["無論技術如何進步，絕對收斂假說∈及相對收斂假說於此均不成立", "技術進步會導致各國經濟成長率高於技術進步率，則相對收斂假說不成立，但絕對收斂假說會 成立", "技術進步下，各國經濟成長率會等於技術進步率，則絕對收斂假說不成立，但相對收斂假說會 成立", "無論經濟成長率與技術進步率關係為何，絕對收斂假說及相對收斂假說均成立 32460、32760"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00078', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '當皮古效果（Pigoueffect）存在時，下列敘述何者正確？', '["總合供給線呈正斜率", "總合供給線呈垂直線", "總合需求線呈負斜率", "總合需求線呈水平線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00079', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '當經濟體系落入流動性陷阱時，下列三項敘述，正確的有幾項？①財政政策沒有排擠效果  ②貨', '["傳統貨幣政策最有效", "0項", "1項", "2項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00080', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '有關新興凱因斯學派模型（NewKeynesianModel）的敘述，下列何者正確？', '["新興凱因斯學派模型認為，並非所有的工資及物價調整都是在同一時間進行，以致於工資與物 價錯開調整現象將使整體物價水準在面臨需求變動之時，呈現緩慢調整現象", "在勞動契約架構下，長期總合供給曲線是正斜率，從而貨幣在短期並非中立性（non-neutrality）", "在物價黏滯（stickiness）下，當民眾能理性預期，清楚知道貨幣政策未來如何走向時，貨幣政 策短期仍然無法影響實質產出", "獨占性競爭與物價黏滯二者同為實質景氣循環模型（RealBusinessCycleModel）與新興凱因斯 學派模型中的重要特性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00081', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '短期總合供給曲線和總合需求曲線交點下的產出水準：', '["永遠小於充分就業的產出", "永遠大於充分就業的產出", "永遠等於充分就業的產出", "有可能大於、等於或小於充分就業的產出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00082', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '有一個經濟體系，其商品及貨幣市場關係如下： 消費函數：C＝25+0.8(Y－T)； 投資函數：I＝75－40r； 政府課稅：T＝25； 政府支出：G＝25； 貨幣需求：L(Y,r)＝100+Y－200r； 貨幣供給：MS＝600；假設物價指數P＝1。 如果政府希望減少稅賦以此補貼民眾，因此決定減少1元的稅賦，但又不願意降低政府支出，因此 要由中央銀行多印1元的貨幣以支應政府原來的支出。則國民所得Y變化為何？', '["增加1.5元", "增加2.5元", "減少1.5元", "減少2.5元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00083', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '假定中央銀行出售4,000萬元國庫券給商業銀行，而存款準備金比率為20%，則其效果為何？', '["超額準備金減少800萬元", "超額準備金減少2億元", "貨幣供給減少約2億元", "貨幣供給減少約4億元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL),
  ('heelevel3-9e7ddffc-moex-00084', 'heelevel3-9e7ddffc', 'heelevel3-9e7ddffc-moex-112-d3ff7f6b', 'sub-heelevel3-9e7ddffc-01', NULL, 'single_choice', '若消費函數為C=Ca+bYd，Ca為自發性消費支出。當可支配所得Yd=10,000時，消費支出C=20,000， 邊際消費傾向b等於0.6，下列敘述何者正確？', '["誘發性消費支出等於10,000", "自發性消費支出等於6,000", "平均消費支出為0.6", "自發性消費支出等於14,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:49+00:00", "source_pdf_sha1": "5ceaffa29b17", "answer_pdf_sha1": "455adc10cc30", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "醫務管理"}'::jsonb, NULL)
